--
-- Name: auto_extract_id_card_last4(); Type: FUNCTION; Schema: public; Owner: seraph
--

CREATE FUNCTION public.auto_extract_id_card_last4() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
      BEGIN
        IF NEW.id_card_number IS NOT NULL THEN
          NEW.id_card_last4 = RIGHT(NEW.id_card_number, 4);
        END IF;
        RETURN NEW;
      END;
      $$;


ALTER FUNCTION public.auto_extract_id_card_last4() OWNER TO seraph;

--
-- Name: sync_apple_password_to_recipients(); Type: FUNCTION; Schema: public; Owner: seraph
--

CREATE FUNCTION public.sync_apple_password_to_recipients() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
      BEGIN
        UPDATE recipients
        SET
          apple_id = NEW.apple_id,
          password = NEW.password,
          updated_at = CURRENT_TIMESTAMP
        WHERE apple_id_ref = NEW.id
          AND (
            apple_id IS DISTINCT FROM NEW.apple_id
            OR password IS DISTINCT FROM NEW.password
          );

        RETURN NEW;
      END;
      $$;


ALTER FUNCTION public.sync_apple_password_to_recipients() OWNER TO seraph;

--
-- Name: sync_bound_apple_id_info(); Type: FUNCTION; Schema: public; Owner: seraph
--

CREATE FUNCTION public.sync_bound_apple_id_info() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
      BEGIN
        IF NEW.apple_id_ref IS NULL THEN
          NEW.apple_id = NULL;
          NEW.password = NULL;
        ELSE
          SELECT apple_id, password
          INTO NEW.apple_id, NEW.password
          FROM apple_ids
          WHERE id = NEW.apple_id_ref;
        END IF;

        RETURN NEW;
      END;
      $$;


ALTER FUNCTION public.sync_bound_apple_id_info() OWNER TO seraph;

